class Solution {
public:
    long long minSumSquareDiff(vector<int>& nums1, vector<int>& nums2, int k1, int k2) {
        int n = nums1.size();
        long long diff = 0;
        for (int i = 0; i < n; i++) {
            diff += (nums1[i] - nums2[i]) * (nums1[i] - nums2[i]);
        }
        int k1_used = 0;
        int k2_used = 0;
        sort(nums1.begin(), nums1.end());
        sort(nums2.begin(), nums2.end());
        for (int i = 0; i < n; i++) {
            if (nums1[i] > nums2[i]) {
                if (k1_used < k1) {
                    nums1[i]--;
                    k1_used++;
                }
            } else if (nums2[i] > nums1[i]) {
                if (k2_used < k2) {
                    nums2[i]--;
                    k2_used++;
                }
            }
        }
        diff = 0;
        for (int i = 0; i < n; i++) {
            diff += (nums1[i] - nums2[i]) * (nums1[i] - nums2[i]);
        }
        return diff;
    }
};
